using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class QualityTraining : TrainingContentBase
{
    public QualityTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quality Overview",
            Slug = "quality-overview",
            Summary = "What the Quality module does: QC templates, inspections, lot tracking, SPC, NCRs, CAPAs, ECOs, and gages — and how quality connects to jobs, parts, and production.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/quality"]""",
            Tags = """["quality","qc","inspection","lot","spc","ncr","capa","eco","gage"]""",
            ContentJson = """{"body":"## Quality Overview\n\nThe Quality module is your central hub for quality control and assurance across the entire manufacturing process. It brings together inspections, lot traceability, statistical process control (SPC), non-conformance reports (NCRs), corrective/preventive actions (CAPAs), engineering change orders (ECOs), and gage management — all in one place.\n\n### QC Templates\n\nTemplates are reusable checklists of inspection checks. Each template has a name, an optional description, and an optional link to a specific part, and it carries checklist items — each item has a description, an optional specification (the expected value or tolerance), a sort order, and a required flag. Templates are set up ahead of time for your site (by an administrator); the Quality page itself does not yet include a template builder. When you create an inspection you pick an existing template from a menu, and its checklist items are attached to that inspection for traceability.\n\n### QC Inspections\n\nInspections are the core quality records. Each inspection is linked to an inspector (automatically the current user) and can optionally reference a job, a QC template, and a lot number. The New Inspection form captures exactly four fields — Template, Job ID, Lot Number, and Notes — and the inspection starts as In Progress. Marking each individual check as passed or failed is not yet available on the Quality page; today the page is for creating and tracking inspections. Once results exist, the list shows status — In Progress, Passed, or Failed — and a summary counting how many checks passed out of the total (e.g., 5/6).\n\n### Lot Tracking\n\nThe Lots tab tracks material lot records for traceability. Each lot has a unique lot number, is linked to a part, and records quantity, optional job reference, supplier lot number, expiration date, and notes. The traceability feature lets you click any lot and see every linked record: jobs that used this lot, production runs, purchase orders, bin locations where the material is stored, and QC inspections performed against it. This is critical for recall management and regulatory compliance.\n\n### SPC (Statistical Process Control)\n\nSPC provides real-time process monitoring through three sub-tabs:\n- **SPC Charts** — X-bar and Range control charts for any measured characteristic. Shows control limits (UCL, LCL, center line), spec limits (USL, LSL), and flags out-of-control points.\n- **SPC Data Entry** — Record measurement subgroups for a selected characteristic. Each subgroup contains multiple readings; the system calculates mean, range, standard deviation, and detects OOC conditions automatically.\n- **OOC Events** — Lists all out-of-control events with severity (Warning, Out of Control, Out of Spec), acknowledgment tracking, and the ability to create a CAPA directly from an OOC event.\n\nSPC characteristics are defined per part and optionally per operation. Each characteristic specifies nominal value, upper/lower spec limits, sample size, measurement type (variable or attribute), unit of measure, decimal places, and gage reference. Process capability indices (Cp, Cpk, Pp, Ppk) are calculated automatically.\n\n### NCRs (Non-Conformance Reports)\n\nNCRs document quality failures. Each NCR has a unique NCR number, type (Internal, Supplier, or Customer), and is linked to a part. NCRs track the detection stage (Receiving, In Process, Final Inspection, Shipping, Customer, Audit), affected and defective quantities, containment actions, and disposition (Use As Is, Rework, Scrap, Return to Vendor, Sort & Screen, Concession). NCRs flow through statuses: Open, Under Review, Contained, Dispositioned, Closed. Material and labor cost impact are tracked for Cost of Poor Quality (COPQ) analysis. NCRs can link to jobs, production runs, lots, sales orders, purchase orders, QC inspections, customers, and vendors.\n\n### CAPAs (Corrective and Preventive Actions)\n\nCAPAs drive systematic problem resolution. The Create CAPA dialog captures the type (Corrective or Preventive), the source (NCR, Customer Complaint, Internal Audit, External Audit, SPC Out of Control, Management Review, or Other), a title, a problem description, an optional impact description, an owner, a priority (1 = Critical through 5 = Informational), and a due date. A new CAPA starts in the Open status and then advances one phase at a time using the forward-arrow action in the list: Open → Root Cause Analysis → Action Planning → Implementation → Verification → Effectiveness Check → Closed. Root-cause methods (5 Whys, Fishbone, Fault Tree, 8D, Pareto, Is/Is-Not), the root-cause write-up, CAPA tasks, and the effectiveness-check date are part of the CAPA model but are not entered in the create dialog — they belong to the phase work that follows, and the page tracks task progress as a completed/total count column.\n\n### ECOs (Engineering Change Orders)\n\nECOs manage controlled changes to parts, processes, and documentation. Each ECO has a number, title, description, change type (New, Revision, Obsolescence, Cost Reduction, Quality Improvement), priority (Low, Normal, High, Critical), and flows through statuses: Draft, Review, Approved, In Implementation, Implemented, Cancelled. ECOs track affected items (parts, BOMs, operations) with old/new values and implementation status.\n\n### Gages\n\nThe Gages tab manages measurement instruments and their calibration lifecycle. Each gage has a number, description, type, manufacturer, model, serial number, and accuracy/range/resolution specifications. Gages track calibration interval (in days), last calibration date, and next calibration due date. Statuses include In Service, Due for Calibration, Out for Calibration, Out of Service, and Retired. Each gage maintains a history of calibration records with result (Pass, Fail, Adjusted, Out of Tolerance), lab name, certificate file, standards used, and as-found/as-left conditions.\n\n### How Quality Connects to Other Features\n\n**Jobs:** Inspections link to jobs so you can see all quality checks performed for a specific job. NCRs reference the job where the defect was found.\n\n**Parts:** Templates and SPC characteristics are defined per part. NCRs identify the defective part. Lot records trace material back to specific parts.\n\n**Lots:** Lot numbers thread through inspections, production runs, purchase orders, and bin locations — providing full material traceability from receipt to shipment.\n\n**Scanner Integration:** The quality page responds to barcode scans. On the Inspections tab, a scan fills the search field. On the Lots tab, a scan fills the lot search field. This enables quick lookup of parts or lots on the shop floor.\n\n### When to Use Quality\n\n- When performing incoming, in-process, or final inspections\n- When tracking material lots for traceability and recall readiness\n- When monitoring process stability with SPC charts\n- When documenting non-conformances and driving corrective actions\n- When managing engineering changes to parts or processes\n- When tracking gage calibration schedules and records","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quality — Guided Tour",
            Slug = "quality-walkthrough",
            Summary = "A guided tour of the quality page: nine tabs covering inspections, lots, SPC, NCRs, CAPAs, ECOs, and gages.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/quality"]""",
            Tags = """["quality","qc","inspection","walkthrough"]""",
            ContentJson = """{"appRoute":"/quality","startButtonLabel":"Tour Quality","steps":[{"element":".tab-bar","popover":{"title":"Quality Tabs","description":"Quality has nine tabs: QC Inspections, Lot Tracking, SPC Charts, SPC Data Entry, OOC Events, NCRs, CAPAs, ECOs, and Gages. Each one covers a different part of quality work. Click a tab to switch to it.","side":"bottom"}},{"element":".tab:nth-child(1)","popover":{"title":"QC Inspections Tab","description":"Opens by default. Shows all inspections with the date, job, template, inspector, lot number, status, and how many checks passed. Statuses are In Progress, Passed, and Failed, each in its own color. Filter by status, or click 'New Inspection' to add one.","side":"bottom"}},{"element":"[data-testid='new-inspection-btn']","popover":{"title":"New Inspection Button","description":"Opens a small form with four fields. Pick a QC template (optional — it pulls in that template's checklist), enter a job and lot number, and add notes. You're recorded as the inspector, and the inspection starts as In Progress. This page creates and tracks inspections; you don't tick off each check here yet.","side":"bottom"}},{"element":".tab:nth-child(2)","popover":{"title":"Lot Tracking Tab","description":"Lists material lots with their lot and part number, quantity, job, supplier lot, and dates. Search by lot or part number. Click the trace button on any row to see everything tied to that lot: jobs, production runs, purchase orders, storage locations, and inspections.","side":"bottom"}},{"element":".tab:nth-child(3)","popover":{"title":"SPC Charts Tab","description":"Shows control charts for anything you measure. Pick a characteristic from the side list. The chart plots your readings, marks the control and spec limits and the center line, and highlights any point that falls outside the normal range. Capability scores (Cp, Cpk, Pp, Ppk) appear beside it.","side":"bottom"}},{"element":".tab:nth-child(4)","popover":{"title":"SPC Data Entry Tab","description":"Record measurement readings for a characteristic. Pick one from the side list, then enter each set of readings. The system works out the average, range, and spread, and flags anything outside the normal range for you.","side":"bottom"}},{"element":".tab:nth-child(5)","popover":{"title":"OOC Events Tab","description":"Lists every reading that fell outside the normal range. Each one shows the characteristic, part, when it happened, why it was flagged, how serious it is, and its status. You can mark an event as reviewed or start a CAPA from it right here.","side":"bottom"}},{"element":".tab:nth-child(6)","popover":{"title":"NCRs Tab","description":"Non-Conformance Reports record quality problems. Each row shows the NCR number, type (Internal, Supplier, or Customer), part, how many are affected, status, and cost impact. Filter by type and status. Create new reports or decide what happens to the material (use as is, rework, scrap, return to vendor, sort and screen, or accept by concession).","side":"bottom"}},{"element":".tab:nth-child(7)","popover":{"title":"CAPAs Tab","description":"Corrective and Preventive Actions help you fix problems for good. Each row shows the CAPA number, type, title, owner, priority, status, due date, and task progress. New CAPA asks for the type, source, title, problem, owner, priority, and due date. Use the forward arrow on a row to move it through its phases: Open, Root Cause Analysis, Action Planning, Implementation, Verification, Effectiveness Check, then Closed.","side":"bottom"}},{"element":".tab:nth-child(8)","popover":{"title":"ECOs Tab","description":"Engineering Change Orders track approved changes to parts, processes, and documents. Each row shows the ECO number, title, change type, status, priority, and how many items it affects. Create, review, and follow a change through to completion.","side":"bottom"}},{"element":".tab:nth-child(9)","popover":{"title":"Gages Tab","description":"Tracks your measuring tools and their calibration. Each row shows the gage number, description, type, status, when the next calibration is due, and how many calibration records it has. Click a gage to see its full detail and history, or record a new calibration with the result, lab, certificate, and before-and-after condition.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quality Field Reference",
            Slug = "quality-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, column, and action across all nine Quality tabs.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/quality"]""",
            Tags = """["quality","qc","inspection","reference"]""",
            ContentJson = """{"title":"Quality Field Reference","groups":[{"heading":"QC Template Fields (predefined — no builder UI)","items":[{"label":"Name (required)","value":"Names the checklist template, such as 'Incoming Material Inspection', 'Final Assembly QC', or 'Dimensional Check'. Templates are set up ahead of time for your site; the Quality page has no template builder. You pick an existing template when you create an inspection."},{"label":"Description","value":"Optional. Explains what the template is for or when to use it."},{"label":"Part","value":"Optional. Ties the template to a specific part, so it's suggested whenever you inspect that part."},{"label":"Active","value":"An on/off switch. Active templates show up in the list you pick from when creating an inspection. On by default."}]},{"heading":"QC Checklist Item Fields (template data — predefined)","items":[{"label":"Description (required)","value":"What the inspector checks, such as 'Surface finish within Ra 32' or 'Dimension A = 2.500 +/- 0.005'. These are set on the template itself, not from the Quality page."},{"label":"Specification","value":"Optional. The expected value, tolerance, or pass/fail rule. Shown next to the check during the inspection."},{"label":"Sort Order","value":"Sets the order the checks appear in. Lower numbers come first."},{"label":"Required","value":"An on/off switch. When on, this check must be marked passed or failed before the inspection can be finished. On by default."}]},{"heading":"Inspection Form Fields","items":[{"label":"Template","value":"Optional. Pick a template to fill the inspection with its checklist items."},{"label":"Job ID","value":"Optional. Ties the inspection to a specific job."},{"label":"Lot Number","value":"Optional. Links the inspection to a material lot for traceability."},{"label":"Notes","value":"Optional. Free-form notes about the inspection."}]},{"heading":"Inspection Result Fields (data model — no entry surface yet)","items":[{"label":"Description","value":"The check being done, filled in from the checklist item. These per-check results are stored on the inspection but can't be entered on the Quality page yet — the page creates and tracks inspections rather than scoring each check."},{"label":"Passed","value":"Whether this one check passed or failed."},{"label":"Measured Value","value":"The value you actually measured, such as '2.503' or 'Ra 28'."},{"label":"Notes","value":"The inspector's notes for this one check."}]},{"heading":"Inspection Statuses","items":[{"label":"In Progress (yellow)","value":"The inspection is underway and results are being recorded."},{"label":"Passed (green)","value":"Every required check passed. The inspection is done and passing."},{"label":"Failed (red)","value":"One or more required checks failed. This may start an NCR or put the job on hold."}]},{"heading":"Inspections Table Columns","items":[{"label":"Date","value":"When the inspection was created. Sortable."},{"label":"Job","value":"The linked job, or a dash if none. Sortable."},{"label":"Template","value":"The template used, or a dash if none. Sortable."},{"label":"Inspector","value":"Who did the inspection. Sortable."},{"label":"Lot Number","value":"The material lot inspected. Sortable."},{"label":"Status","value":"In Progress (yellow), Passed (green), or Failed (red). Sortable and filterable."},{"label":"Results Summary","value":"How many checks passed out of the total, such as '5/6'. A dash if none are recorded."}]},{"heading":"Lot Record Fields","items":[{"label":"Part (required)","value":"The part this lot is for."},{"label":"Quantity (required)","value":"How many units are in the lot. Must be at least 1. Starts at 1."},{"label":"Lot Number","value":"Optional. Leave it blank and the system makes a unique one for you."},{"label":"Job ID","value":"Optional. Ties the lot to a production job."},{"label":"Supplier Lot Number","value":"Optional. The vendor's lot number for incoming material."},{"label":"Notes","value":"Optional. Notes about the lot, such as storage or special handling."}]},{"heading":"Lot Table Columns","items":[{"label":"Lot Number","value":"The lot's unique number. Sortable."},{"label":"Part #","value":"The part this lot belongs to. Sortable."},{"label":"Description","value":"The part's description. Sortable."},{"label":"Quantity","value":"How many units are in the lot. Sortable."},{"label":"Job","value":"The linked job, or a dash. Sortable."},{"label":"Supplier Lot","value":"The vendor's lot number, or a dash. Sortable."},{"label":"Expires","value":"The expiration date, or a dash. Sortable."},{"label":"Created","value":"When the lot was created. Sortable."},{"label":"Actions","value":"A trace button that opens the traceability view for the lot."}]},{"heading":"Traceability Dialog Sections","items":[{"label":"Header","value":"Shows the part number and description for the lot."},{"label":"Jobs","value":"Every job that used this lot, with its number and title."},{"label":"Production Runs","value":"Linked production runs, with their number and status."},{"label":"Purchase Orders","value":"The purchase orders that supplied this material, with their number and vendor."},{"label":"Bin Locations","value":"Where the material is stored, with the location and quantity."},{"label":"QC Inspections","value":"Inspections against this lot, with their status, inspector, and date."}]},{"heading":"SPC Characteristic Fields","items":[{"label":"Part (required)","value":"The part being measured."},{"label":"Operation","value":"Optional. The exact step where the measurement is taken."},{"label":"Name (required)","value":"What you're measuring, such as 'Diameter A' or 'Surface Roughness'."},{"label":"Description","value":"Optional. More detail about the characteristic."},{"label":"Measurement Type","value":"Variable (a measured number) or Attribute (pass/fail). Starts on Variable."},{"label":"Nominal Value (required)","value":"The target, or ideal, value."},{"label":"Upper Spec Limit (required)","value":"The highest acceptable value (USL)."},{"label":"Lower Spec Limit (required)","value":"The lowest acceptable value (LSL)."},{"label":"Unit of Measure","value":"Optional, such as 'mm', 'inches', or 'Ra'."},{"label":"Decimal Places","value":"How many decimal places to show for measurements."},{"label":"Sample Size","value":"How many readings you take at a time, such as 5."},{"label":"Sample Frequency","value":"Optional. How often to measure, such as 'Every 50 parts' or 'Hourly'."},{"label":"Gage","value":"Optional. Links to a gage from the Gages tab for traceability."},{"label":"Active","value":"An on/off switch. Inactive characteristics are hidden from data entry."},{"label":"Notify on OOC","value":"An on/off switch. When on, you're notified whenever a reading falls outside the normal range."}]},{"heading":"SPC Chart Elements","items":[{"label":"UCL (Upper Control Limit)","value":"Calculated from measurement data. Upper boundary of normal process variation."},{"label":"LCL (Lower Control Limit)","value":"Calculated from measurement data. Lower boundary of normal process variation."},{"label":"Center Line","value":"Process mean (X-bar chart) or average range (R chart)."},{"label":"USL / LSL","value":"Spec limits from the characteristic definition. Not the same as control limits."},{"label":"OOC Points","value":"Points that violate Western Electric rules are highlighted on the chart."},{"label":"Cp / Cpk","value":"Short-term process capability. Cp = potential, Cpk = actual (accounts for centering)."},{"label":"Pp / Ppk","value":"Long-term process performance. Pp = potential, Ppk = actual."}]},{"heading":"OOC Event Fields","items":[{"label":"Severity","value":"Warning (minor rule violation), Out of Control (major rule violation), Out of Spec (beyond USL/LSL)."},{"label":"Status","value":"Open (detected, not yet reviewed), Acknowledged (reviewed by quality), CAPA Created (linked to corrective action), Resolved (root cause addressed)."},{"label":"Rule Name","value":"Which Western Electric rule was violated (e.g., 'Point beyond 3-sigma', 'Run of 7')."},{"label":"Acknowledgment","value":"Who acknowledged, when, and their notes."}]},{"heading":"NCR Fields","items":[{"label":"NCR Number","value":"A unique number the system assigns."},{"label":"Type (required)","value":"Internal (found in-house), Supplier (incoming material defect), or Customer (customer complaint)."},{"label":"Part (required)","value":"The part that didn't meet spec."},{"label":"Detection Stage (required)","value":"Where it was caught: Receiving, In Process, Final Inspection, Shipping, Customer, or Audit."},{"label":"Description (required)","value":"What the defect is and how it was found."},{"label":"Affected Quantity (required)","value":"How many units are affected in total."},{"label":"Defective Quantity","value":"Optional. How many are actually defective, which may be fewer than affected."},{"label":"Containment Actions","value":"Optional. What you did right away to keep the defect from spreading."},{"label":"Material Cost / Labor Cost","value":"Optional. The cost impact, tracked for cost-of-poor-quality reporting."}]},{"heading":"NCR Statuses","items":[{"label":"Open","value":"NCR created, investigation not yet started."},{"label":"Under Review","value":"Quality team is evaluating the non-conformance."},{"label":"Contained","value":"Immediate containment actions completed. Awaiting disposition."},{"label":"Dispositioned","value":"Formal disposition assigned: Use As Is, Rework, Scrap, Return to Vendor, Sort & Screen, or Concession."},{"label":"Closed","value":"NCR fully resolved. Corrective actions complete if applicable."}]},{"heading":"NCR Disposition Codes","items":[{"label":"Use As Is","value":"Accept the non-conforming material without rework."},{"label":"Rework","value":"Repair or rework the material to bring it into conformance."},{"label":"Scrap","value":"Discard the non-conforming material."},{"label":"Return to Vendor","value":"Send defective material back to the supplier."},{"label":"Sort & Screen","value":"Inspect the entire lot to separate good from defective units."},{"label":"Concession","value":"Accept with customer approval or documented deviation."}]},{"heading":"CAPA Create Dialog Fields","items":[{"label":"Type (required)","value":"Corrective (fix a problem you have) or Preventive (stop one before it happens). Starts on Corrective."},{"label":"Source (required)","value":"Where the CAPA came from: NCR, Customer Complaint, Internal Audit, External Audit, SPC Out of Control, Management Review, or Other."},{"label":"Title (required)","value":"A short name for the issue, up to 500 characters."},{"label":"Problem Description (required)","value":"A full description of the problem."},{"label":"Impact Description","value":"Optional. How the problem affects the business."},{"label":"Owner (required)","value":"The person responsible for seeing the CAPA through. Their name shows in the list."},{"label":"Priority","value":"1 to 5: 1 = Critical, 2 = High, 3 = Medium (the default), 4 = Low, 5 = Informational."},{"label":"Due Date (required)","value":"The target completion date."},{"label":"CAPA Number","value":"A unique number the system assigns when you save."},{"label":"Phase-only fields (NOT in the create dialog)","value":"The root-cause method (5 Whys, Fishbone, Fault Tree, 8D, Pareto, or Is/Is-Not), the write-up, the tasks, and the effectiveness-check date aren't set here. You fill those in as the CAPA moves through its phases after it's opened."}]},{"heading":"CAPA Statuses (advance order)","items":[{"label":"Open","value":"Starting status of every new CAPA. The problem is logged."},{"label":"Root Cause Analysis","value":"Investigating why the problem occurred."},{"label":"Action Planning","value":"Defining the corrective and preventive actions."},{"label":"Implementation","value":"Carrying out the planned actions."},{"label":"Verification","value":"Confirming the actions were completed and effective."},{"label":"Effectiveness Check","value":"Longer-term follow-up to ensure the problem does not recur."},{"label":"Closed","value":"CAPA complete. Advance to the next phase with the forward-arrow button on each open row."}]},{"heading":"ECO Fields","items":[{"label":"ECO Number","value":"A unique number the system assigns."},{"label":"Title (required)","value":"A short name for the change."},{"label":"Description (required)","value":"A full description of what's changing and why."},{"label":"Change Type (required)","value":"New, Revision, Obsolescence, Cost Reduction, or Quality Improvement."},{"label":"Priority (required)","value":"Low, Normal, High, or Critical."},{"label":"Reason for Change","value":"Optional. Why the change is needed."},{"label":"Impact Analysis","value":"Optional. How the change affects production, cost, and quality."},{"label":"Effective Date","value":"Optional. When the change takes effect."}]},{"heading":"ECO Statuses","items":[{"label":"Draft","value":"ECO created, not yet submitted for review."},{"label":"Review","value":"Submitted for review by stakeholders."},{"label":"Approved","value":"Change approved, ready for implementation."},{"label":"In Implementation","value":"Change is actively being implemented."},{"label":"Implemented","value":"Change fully implemented and verified."},{"label":"Cancelled","value":"ECO cancelled, change will not be made."}]},{"heading":"Gage Fields","items":[{"label":"Description (required)","value":"What the gage is, such as 'Digital Caliper 0-6\"' or 'Outside Micrometer 1-2\"'."},{"label":"Gage Type","value":"Optional. The kind of instrument, such as 'Caliper', 'Micrometer', 'CMM', or 'Gauge Block'."},{"label":"Manufacturer","value":"Optional. Who made it, such as 'Mitutoyo' or 'Starrett'."},{"label":"Model","value":"Optional. The maker's model number."},{"label":"Serial Number","value":"Optional. The instrument's unique serial number."},{"label":"Calibration Interval (required)","value":"How many days between calibrations, such as 365 for yearly."},{"label":"Accuracy Spec","value":"Optional. Its rated accuracy, such as '+/- 0.001\"'."},{"label":"Range Spec","value":"Optional. Its measuring range, such as '0-6 inches'."},{"label":"Resolution","value":"Optional. Its smallest step, such as '0.0005\"'."},{"label":"Location","value":"Optional. Where the gage is kept."},{"label":"Asset","value":"Optional. Links the gage to an asset record if it has one."},{"label":"Notes","value":"Optional. Anything else about the gage."}]},{"heading":"Gage Statuses","items":[{"label":"In Service (green)","value":"Gage is calibrated and available for use."},{"label":"Due for Calibration (yellow)","value":"Calibration interval has elapsed. Gage should not be used until recalibrated."},{"label":"Out for Calibration (blue)","value":"Gage has been sent to a calibration lab and is awaiting return."},{"label":"Out of Service (red)","value":"Gage is damaged or otherwise unusable. Requires repair."},{"label":"Retired (gray)","value":"Gage permanently removed from service."}]},{"heading":"Calibration Record Fields","items":[{"label":"Calibrated On (required)","value":"When the calibration was done."},{"label":"Result (required)","value":"Pass (within spec), Fail (out of tolerance, can't be fixed), Adjusted (out of tolerance, then corrected), or Out of Tolerance (out of spec, may need a closer look)."},{"label":"Lab Name","value":"Optional. The outside lab, or 'In-House'."},{"label":"Certificate File","value":"Optional. The calibration certificate PDF."},{"label":"Standards Used","value":"Optional. The traceable standards used during calibration."},{"label":"As Found Condition","value":"Optional. The gage's condition before calibration."},{"label":"As Left Condition","value":"Optional. The gage's condition after calibration."},{"label":"Notes","value":"Optional. Any extra calibration notes. The person who recorded it is saved automatically."}]},{"heading":"Gage Table Columns","items":[{"label":"Gage #","value":"The gage's number, assigned automatically. Sortable."},{"label":"Description","value":"What the gage is. Sortable."},{"label":"Type","value":"The kind of gage. Sortable."},{"label":"Status","value":"The gage's status, in its own color. Sortable and filterable."},{"label":"Next Cal Due","value":"When the next calibration is due. Sortable."},{"label":"Cal Records","value":"How many calibration records the gage has. Sortable."}]},{"heading":"Buttons and Actions","items":[{"label":"New Inspection","value":"Starts a new inspection. On the Inspections tab."},{"label":"New Lot","value":"Starts a new lot. On the Lots tab."},{"label":"New Characteristic","value":"Adds a new SPC characteristic. On the SPC Charts and SPC Data Entry tabs."},{"label":"New NCR","value":"Starts a new non-conformance report. On the NCRs tab."},{"label":"New CAPA","value":"Starts a new corrective or preventive action. On the CAPAs tab."},{"label":"New ECO","value":"Starts a new engineering change order. On the ECOs tab."},{"label":"New Gage","value":"Adds a new gage. On the Gages tab."},{"label":"View Traceability","value":"Opens the traceability view showing everything tied to a lot. On each lot row."},{"label":"Acknowledge OOC","value":"Marks an out-of-range event as reviewed. On each OOC event."},{"label":"Create CAPA from OOC","value":"Starts a CAPA linked to the event. On each unresolved OOC event."},{"label":"Create CAPA from NCR","value":"Starts a corrective action linked to the NCR."},{"label":"Disposition NCR","value":"Opens a panel to decide what happens to the material — use as is, rework, scrap, and so on."},{"label":"Record Calibration","value":"Records a calibration for the selected gage."}]},{"heading":"Scanner Integration","items":[{"label":"Inspections tab","value":"Scanning a barcode fills the inspection search box with the scanned value."},{"label":"Lots tab","value":"Scanning a barcode fills the lot search box with the scanned value."},{"label":"When it's active","value":"The scanner only reads codes while the Quality page is open."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quality Knowledge Check",
